select id, tenant_id, tenant_name, status, description, created_at, updated_at, created_by
from batch.tenant


        and (tenant_id ilike concat('%', #{keyword}, '%')
          or tenant_name ilike concat('%', #{keyword}, '%'))


        and status = #{status}


order by id desc


    limit #{pageRequest.pageSize}
    offset #{offset}

select count(1) from batch.tenant
and (tenant_id ilike concat('%', #{keyword}, '%') or tenant_name ilike concat('%', #{keyword}, '%'))
and status = #{status}
